+*{
+    margin: 0;
+    padding: 0;
+    box-sizing: border-box;
+
+}
+ 
+.Navbar {
+     /*color: orange;*/
+    font-size: 2rem;display: flex;
+    border: 1px solid black;
+    padding: 1rem;
+    background-color:darkred;
+  }
+.Navbar a{
+    color: white;
+    margin-left: 1rem;
+    text-decoration: none;
+
+}
+ .container img {
+    width:70rem;
+    height:30rem;position: relative;
+    /*margin:-2rem auto;*/
+     margin-left:-5rem ;
+     filter: brightness(30%) contrast(110%);
+     object-fit: cover;
+}.container button{
+    background-color: #9c1818;
+margin-bottom: 10rem;      position: absolute;
+ margin-left:30rem;
+
+  }
+  img{
+    width:20rem;
+    height:20rem;
+  }
+ .app ul li img { width:20rem;
+ height:20rem;
+ }.app ul li{
+    list-style: none;
+   }
+
+.Product-cards{
+border: 2px solid red;
+width:18rem;
+display:flex;
+margin-left:22rem;
+gap:50rem;
+}
+.Product-cards img {
+    width:8rem;
+    height:8rem;
+
+}
+* .app ul {
+    display:flex;
+    gap: 5px;
+    overflow-x: auto;
+    /*   enables mouse scroll*/
+    padding: 5px;
+    /* white-space: nowrap;  */
+}
+.app ul li  img{
+    width: 250px;
+    height: 250px;
+    object-fit: cover;
+    border:4px solid #9c1818;
+    flex-shrink: 0;
+    display:flex;
+    border-radius: 899%;
+}
+.card-body ul li img {
+    width: 20rem;
+    height: 15rem;    border-radius: 10px;
+}
+.card-body{
+    padding:2rem;
+}
+.card-body ul {
+   display: flex;
+}
+.card-body ul li {
+    border: 1px solid #9c1818;
+    /*gap: 10px;*/
+    border-radius: 16px;
+    list-style: none;    /*padding: 5px;*/
+
+}.About-section img{
+    width:25rem;
+    border-radius: 8rem 2rem 3rem 4rem;
+    height:28rem;
+    /*padding:1rem;*/
+
+ }.About-section {
+    display: flex;
+    padding:0.2rem;
+
+   }
+  .contact-sec{
+      background-image: url("contect.jpg ");
+     width: 70rem;
+      filter: brightness(70%) contrast(110%);
+      object-fit: cover;
+      height: 30rem;
+      color: darkred;
+      background-size: cover;
+      background-position: center;
+    display: flex;
+
+  }
+  .contact-sec ul{
+      margin: 3rem;
+
+      font-size: 2rem;
+      /*background-color: ;*/
+  }
+  .contact-sec h1 {color: #0e30bc;
+  }
+.contact-sec h3 {color: #0e30bc;
+
+}
+.contact-sec h2 {color: #0e30bc;}
+.Burger-sec ul li img {
+    width: 20rem;
+    height: 15rem;    border-radius: 10px;
+}
+.Burger-sec{
+    padding:2rem;
+}
+.Burger-sec ul {
+    display: flex;
+}
+.Burger-sec ul li {
+    border: 1px solid #9c1818;
+    /*gap: 10px;*/
+    border-radius: 16px;
+    list-style: none;    /*padding: 5px;*/
+}
+.data-sec{
+    background-color: #0e30bc;
+}
